scwin.gr_results_onbeforeedit = function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  var colId = gr_results.getColumnID(columnIndex);
  if (ds_results.getCellData(row, "closeYn") == '1') {
    return false;
  }
  switch (colId) {
    case "clntVat":
      if (ds_results.getCellData(row, "taxnClsCd") != '01') {
        return false;
      }
      break;
    default:
      break;
  }
};
scwin.gr_results_onheaderclick = function (headerId) {
  if (headerId == "chkHeader") {
    var bCheck = gr_results.getHeaderValue(headerId);
    gr_results.checkAll('chk', bCheck);
  }
};
